$.Tq=A.Td('#version 300 es\n// Skinning vert-shader ES3 //////////\n#define ENABLE_SKINNING\n\nlayout(location = 0) in highp vec3 inVertex;\nlayout(location = 4) in mediump vec4 inBoneIndex; // Back to vec4 for buffer compatibility\nlayout(location = 5) in mediump vec4 inBoneWeight;\n\n// skinning mesh part: bone\nuniform mediump int BoneCount;\nuniform highp mat4 BoneMatrixArray[32];\n\n#ifdef ENABLE_NORMAL\nlayout(location = 2) in mediump vec3 inNormal;\nvoid ComputeSkinningVertex(out highp vec4 objVert, out mediump vec3 objNormal)\n#else\nvoid ComputeSkinningVertex(out highp vec4 objVert)\n#endif // ENABLE_NORMAL\n{\n    highp vec4 srcVert = vec4(inVertex, 1.0);\n    \n    // Cast vec4 to ivec4 for lookup\n    ivec4 boneIndex = ivec4(inBoneIndex + 0.5);\n\n    objVert = BoneMatrixArray[boneIndex.x] * srcVert * inBoneWeight.x;\n#ifdef ENABLE_NORMAL\n    objNormal = mat3(BoneMatrixArray[boneIndex.x]) * inNormal * inBoneWeight.x;\n#endif // ENABLE_NORMAL\n\n    if (BoneCount > 1)\n    {\n        objVert += BoneMatrixArray[boneIndex.y] * srcVert * inBoneWeight.y;\n#ifdef ENABLE_NORMAL\n        objNormal += mat3(BoneMatrixArray[boneIndex.y]) * inNormal * inBoneWeight.y;\n#endif // ENABLE_NORMAL\n        if (BoneCount > 2)\n        {\n            objVert += BoneMatrixArray[boneIndex.z] * srcVert * inBoneWeight.z;\n#ifdef ENABLE_NORMAL\n            objNormal += mat3(BoneMatrixArray[boneIndex.z]) * inNormal * inBoneWeight.z;\n#endif // ENABLE_NORMAL\n            if (BoneCount > 3)\n            {\n                objVert += BoneMatrixArray[boneIndex.w] * srcVert * inBoneWeight.w;\n#ifdef ENABLE_NORMAL\n                objNormal += mat3(BoneMatrixArray[boneIndex.w]) * inNormal * inBoneWeight.w;\n#endif // ENABLE_NORMAL\n            }\n        }\n    }\n#ifdef ENABLE_NORMAL\n    objNormal = normalize(objNormal);\n#endif // ENABLE_NORMAL\n}\n\n#version 300 es\n// Simple vert-shader ES3 //////////\n// NOTICE: "Skinning.es3.vert" must be added before this file\n#ifndef ENABLE_SKINNING\nlayout(location = 0) in highp vec3 inVertex;\t\t// vertex-data\n#endif // ENABLE_SKINNING\n\nuniform lowp vec4 uColor;\nout lowp vec4 DestinationColor;\n// eye-space for camera-viewer\nuniform highp mat4 ModelviewProjection;\n\t\t  \nvoid main(void)\n{\n\thighp vec4 objVert = vec4(inVertex, 1.0);\n\n#ifdef ENABLE_SKINNING\n\tif (BoneCount > 0)\n\t{\n\t\tComputeSkinningVertex(objVert);\n\t}\n#endif // ENABLE_SKINNING\n\n    DestinationColor = uColor; // use uniform color\n    gl_Position = ModelviewProjection * objVert;\t// pre-compute Projection * Modelview\n}\n\n',u.w)
$.ael=A.Td("#version 300 es\n// Skybox vert-shader ES3 //////////\nlayout(location = 0) in highp vec3 inVertex;\t\t// vertex-data\n\nuniform lowp vec4 uColor;\nout lowp vec4 DestinationColor;\nout mediump vec3 TexCoordDirOut;\n// eye-space for camera-viewer\nuniform highp mat4 ModelviewProjection;\n\nvoid main(void)\n{\n\thighp vec4 objVert = vec4(inVertex, 1.0);\n\n\tTexCoordDirOut = objVert.xyz;\n\tDestinationColor = uColor;\n\tgl_Position = ModelviewProjection * objVert;\t// pre-compute Projection * Modelview\n}\n\n",u.n)
$.ij=A.Td("#version 300 es\n// Rect vert-shader ES3 //////////\nlayout(location = 0) in highp vec3 inVertex;\t\t// vertex-data\nlayout(location = 3) in mediump vec2 inTexCoord;\n\nuniform lowp vec4 uColor;\n\n// eye-space for camera-viewer\nuniform highp mat4 Projection;\t\t// ortho-matrix\nuniform highp mat4 Model;\t\t\t// model-matrix (by screen-object)\n\nuniform highp mat3 uTexMatrix;\t\t// texture-matrix (uv mapping)\nout mediump vec2 TextureCoordOut;\nout lowp vec4 DestinationColor;\n\nvoid main(void)\n{\n\tDestinationColor = uColor;\n\tTextureCoordOut = (uTexMatrix * vec3(inTexCoord, 1.0)).xy;\n    gl_Position = Projection * Model * vec4(inVertex, 1.0);\n}\n\n","#version 300 es\n// Rect frag-shader ES3 //////////\nprecision mediump float;\nin mediump vec2 TextureCoordOut;\nin lowp vec4 DestinationColor;\n\nuniform sampler2D SamplerDiffuse;\t// GL_TEXTURE0\nout vec4 fragColor;\n\nvoid main(void)\n{\n    fragColor = texture(SamplerDiffuse, TextureCoordOut) * DestinationColor;\n}\n\n")
$.aem=A.anL('#define ENABLE_NORMAL \n#version 300 es\n// Skinning vert-shader ES3 //////////\n#define ENABLE_SKINNING\n\nlayout(location = 0) in highp vec3 inVertex;\nlayout(location = 4) in mediump vec4 inBoneIndex; // Back to vec4 for buffer compatibility\nlayout(location = 5) in mediump vec4 inBoneWeight;\n\n// skinning mesh part: bone\nuniform mediump int BoneCount;\nuniform highp mat4 BoneMatrixArray[32];\n\n#ifdef ENABLE_NORMAL\nlayout(location = 2) in mediump vec3 inNormal;\nvoid ComputeSkinningVertex(out highp vec4 objVert, out mediump vec3 objNormal)\n#else\nvoid ComputeSkinningVertex(out highp vec4 objVert)\n#endif // ENABLE_NORMAL\n{\n    highp vec4 srcVert = vec4(inVertex, 1.0);\n    \n    // Cast vec4 to ivec4 for lookup\n    ivec4 boneIndex = ivec4(inBoneIndex + 0.5);\n\n    objVert = BoneMatrixArray[boneIndex.x] * srcVert * inBoneWeight.x;\n#ifdef ENABLE_NORMAL\n    objNormal = mat3(BoneMatrixArray[boneIndex.x]) * inNormal * inBoneWeight.x;\n#endif // ENABLE_NORMAL\n\n    if (BoneCount > 1)\n    {\n        objVert += BoneMatrixArray[boneIndex.y] * srcVert * inBoneWeight.y;\n#ifdef ENABLE_NORMAL\n        objNormal += mat3(BoneMatrixArray[boneIndex.y]) * inNormal * inBoneWeight.y;\n#endif // ENABLE_NORMAL\n        if (BoneCount > 2)\n        {\n            objVert += BoneMatrixArray[boneIndex.z] * srcVert * inBoneWeight.z;\n#ifdef ENABLE_NORMAL\n            objNormal += mat3(BoneMatrixArray[boneIndex.z]) * inNormal * inBoneWeight.z;\n#endif // ENABLE_NORMAL\n            if (BoneCount > 3)\n            {\n                objVert += BoneMatrixArray[boneIndex.w] * srcVert * inBoneWeight.w;\n#ifdef ENABLE_NORMAL\n                objNormal += mat3(BoneMatrixArray[boneIndex.w]) * inNormal * inBoneWeight.w;\n#endif // ENABLE_NORMAL\n            }\n        }\n    }\n#ifdef ENABLE_NORMAL\n    objNormal = normalize(objNormal);\n#endif // ENABLE_NORMAL\n}\n\n#version 300 es\n// Skybox Reflect vert-shader ES3 //////////\n// NOTICE 1: ENABLE_NORMAL must be defined first\n// NOTICE 2: "Skinning.es3.vert" must be added for skinning\n#ifndef ENABLE_SKINNING\nlayout(location = 0) in highp vec3 inVertex;\t\t// vertex-data\nlayout(location = 2) in mediump vec3 inNormal;\n#endif // ENABLE_SKINNING\n\n// object space\nuniform mediump vec3 EyePosition;\t\t\t// eye as camera origin\nuniform lowp vec4 uColor;\n\nout lowp vec4 DestinationColor;\nout mediump vec3 TexCoordDirOut;\n\n// space transformation\nuniform highp mat4 Model;\nuniform highp mat4 ModelviewProjection;\n\nvoid main(void)\n{\n\thighp vec4 objVert = vec4(inVertex, 1.0);\n\tmediump vec3 objNormal = inNormal;\n\n#ifdef ENABLE_SKINNING\n\tif (BoneCount > 0)\n\t{\n\t\tComputeSkinningVertex(objVert, objNormal);\n\t}\n#endif // ENABLE_SKINNING\n\n\tmediump vec3 eyeDir = normalize(objVert.xyz - EyePosition);\t// by object-space\n\tmediump vec3 reflectDir = reflect(eyeDir, objNormal);\t\t// by object-space\n\treflectDir = mat3(Model) * reflectDir;\t\t\t\t\t\t// by world-space\n\n\t// Swizzle to match skybox-cubemap orientation (rotXNeg90)\n\tTexCoordDirOut.x = -reflectDir.x;\n\tTexCoordDirOut.y = reflectDir.z;\n\tTexCoordDirOut.z = -reflectDir.y;\n\n\tDestinationColor = uColor;\n\n    gl_Position = ModelviewProjection * objVert;\t// pre-compute Projection * Modelview\n}\n\n',u.n)
A.aeg('#define ENABLE_NORMAL \n#version 300 es\n// Skinning vert-shader ES3 //////////\n#define ENABLE_SKINNING\n\nlayout(location = 0) in highp vec3 inVertex;\nlayout(location = 4) in mediump vec4 inBoneIndex; // Back to vec4 for buffer compatibility\nlayout(location = 5) in mediump vec4 inBoneWeight;\n\n// skinning mesh part: bone\nuniform mediump int BoneCount;\nuniform highp mat4 BoneMatrixArray[32];\n\n#ifdef ENABLE_NORMAL\nlayout(location = 2) in mediump vec3 inNormal;\nvoid ComputeSkinningVertex(out highp vec4 objVert, out mediump vec3 objNormal)\n#else\nvoid ComputeSkinningVertex(out highp vec4 objVert)\n#endif // ENABLE_NORMAL\n{\n    highp vec4 srcVert = vec4(inVertex, 1.0);\n    \n    // Cast vec4 to ivec4 for lookup\n    ivec4 boneIndex = ivec4(inBoneIndex + 0.5);\n\n    objVert = BoneMatrixArray[boneIndex.x] * srcVert * inBoneWeight.x;\n#ifdef ENABLE_NORMAL\n    objNormal = mat3(BoneMatrixArray[boneIndex.x]) * inNormal * inBoneWeight.x;\n#endif // ENABLE_NORMAL\n\n    if (BoneCount > 1)\n    {\n        objVert += BoneMatrixArray[boneIndex.y] * srcVert * inBoneWeight.y;\n#ifdef ENABLE_NORMAL\n        objNormal += mat3(BoneMatrixArray[boneIndex.y]) * inNormal * inBoneWeight.y;\n#endif // ENABLE_NORMAL\n        if (BoneCount > 2)\n        {\n            objVert += BoneMatrixArray[boneIndex.z] * srcVert * inBoneWeight.z;\n#ifdef ENABLE_NORMAL\n            objNormal += mat3(BoneMatrixArray[boneIndex.z]) * inNormal * inBoneWeight.z;\n#endif // ENABLE_NORMAL\n            if (BoneCount > 3)\n            {\n                objVert += BoneMatrixArray[boneIndex.w] * srcVert * inBoneWeight.w;\n#ifdef ENABLE_NORMAL\n                objNormal += mat3(BoneMatrixArray[boneIndex.w]) * inNormal * inBoneWeight.w;\n#endif // ENABLE_NORMAL\n            }\n        }\n    }\n#ifdef ENABLE_NORMAL\n    objNormal = normalize(objNormal);\n#endif // ENABLE_NORMAL\n}\n\n#version 300 es\n// Simple-lighting vert-shader ES3 //////////\n// NOTICE: "Skinning.es3.vert" must be added before this file\n#ifndef ENABLE_SKINNING\nlayout(location = 0) in highp vec3 inVertex;\t\t// vertex-data\nlayout(location = 2) in mediump vec3 inNormal;\n#endif // ENABLE_SKINNING\n\nuniform lowp vec4 uColor;\n\n// eye-space for camera-viewer\nuniform mat4 ModelviewProjection;\n\n// color combined by light and material\nuniform lowp vec3 ColorAmbient;\t\t// ambient RGB \nuniform lowp vec4 ColorDiffuse;\t\t// diffuse RGBA\nuniform mediump vec4 ColorSpecular;\t// specular RGB, w: shininess\n\n// object-space\nuniform vec3 EyePosition;\t\t// eye as camera origin\nuniform vec3 LightPosition;\t\t// parallel light\n\n// shader variable: from vert to frag\nout lowp vec4 DestinationColor;\n\nvoid main(void) {\n\thighp vec4 objVert = vec4(inVertex, 1.0);\n\tmediump vec3 objNormal = inNormal;\n\n#ifdef ENABLE_SKINNING\n\tif (BoneCount > 0)\n\t{\n\t\tComputeSkinningVertex(objVert, objNormal);\n\t}\n#endif // ENABLE_SKINNING\n\n\t// object-space: normal, light-position, eye-position\n\tvec3 N = objNormal;\n\tvec3 L = LightPosition;\t\t\t\t\t\t\t// parallel light source\n\tvec3 E = normalize(EyePosition - objVert.xyz);\t// vertex to eye\n\tvec3 H = normalize(L + E);\n\n\tfloat df = max(0.0, dot(N, L));\n\tfloat sf = max(0.0, dot(N, H));\n\tsf = pow(sf, ColorSpecular.w);\n\n\tlowp vec3 AmbientDiffuseSpecular = (ColorAmbient + ColorDiffuse.rgb * df) + ColorSpecular.rgb * sf;\n\n\tDestinationColor = vec4(AmbientDiffuseSpecular, uColor.a);\n\tgl_Position = ModelviewProjection * objVert;\t// pre-compute Projection * Modelview\n}\n\n',u.w)
$.anO=A.Td('#version 300 es\n// Simple vert-shader ES3 //////////\n// NOTICE: "Skinning.es3.vert" must be added before this file\n#ifndef ENABLE_SKINNING\nlayout(location = 0) in highp vec3 inVertex;\t\t// vertex-data\n#endif // ENABLE_SKINNING\n\nlayout(location = 3) in mediump vec2 inTexCoord;\n\nuniform lowp vec4 uColor;\nout lowp vec4 DestinationColor;\nout mediump vec2 TextureCoordOut;\n\n// eye-space for camera-viewer\nuniform highp mat4 ModelviewProjection;\n\t\t  \nvoid main(void)\n{\n\thighp vec4 objVert = vec4(inVertex, 1.0);\n\n#ifdef ENABLE_SKINNING\n\tif (BoneCount > 0)\n\t{\n\t\tComputeSkinningVertex(objVert);\n\t}\n#endif // ENABLE_SKINNING\n\n    DestinationColor = uColor; // use uniform color\n    TextureCoordOut = inTexCoord;\n    gl_Position = ModelviewProjection * objVert;\t// pre-compute Projection * Modelview\n}\n\n',"#version 300 es\n// Simple frag-shader ES3 //////////\nprecision mediump float;\nin mediump vec2 TextureCoordOut;\nin lowp vec4 DestinationColor;\n\n#ifdef ENABLE_EXTERNAL_OES\nuniform samplerExternalOES SamplerDiffuse;   // GL_TEXTURE0\n#else\nuniform sampler2D SamplerDiffuse;   // GL_TEXTURE0\n#endif\n\nout vec4 fragColor;\n\nvoid main(void)\n{\n    lowp vec4 texResult = texture(SamplerDiffuse, TextureCoordOut);\t// tex-lookup\n#ifdef ENABLE_TEXTURE0_BGRA\t// iOS, macOS: CVPixelBuffer is BGRA, not RGBA\n\ttexResult = texResult.bgra;\n#endif // ENABLE_TEXTURE0_BGRA\n\n    fragColor = texResult * DestinationColor;\n}\n\n")
