$.aa4=A.aeg("#define ENABLE_NORMAL \n#version 300 es\n// Skinning vert-shader ES3 //////////\n#define ENABLE_SKINNING\n\nlayout(location = 0) in highp vec3 inVertex;\nlayout(location = 4) in mediump vec4 inBoneIndex; // Back to vec4 for buffer compatibility\nlayout(location = 5) in mediump vec4 inBoneWeight;\n\n// skinning mesh part: bone\nuniform mediump int BoneCount;\nuniform highp mat4 BoneMatrixArray[32];\n\n#ifdef ENABLE_NORMAL\nlayout(location = 2) in mediump vec3 inNormal;\nvoid ComputeSkinningVertex(out highp vec4 objVert, out mediump vec3 objNormal)\n#else\nvoid ComputeSkinningVertex(out highp vec4 objVert)\n#endif // ENABLE_NORMAL\n{\n    highp vec4 srcVert = vec4(inVertex, 1.0);\n    \n    // Cast vec4 to ivec4 for lookup\n    ivec4 boneIndex = ivec4(inBoneIndex + 0.5);\n\n    objVert = BoneMatrixArray[boneIndex.x] * srcVert * inBoneWeight.x;\n#ifdef ENABLE_NORMAL\n    objNormal = mat3(BoneMatrixArray[boneIndex.x]) * inNormal * inBoneWeight.x;\n#endif // ENABLE_NORMAL\n\n    if (BoneCount > 1)\n    {\n        objVert += BoneMatrixArray[boneIndex.y] * srcVert * inBoneWeight.y;\n#ifdef ENABLE_NORMAL\n        objNormal += mat3(BoneMatrixArray[boneIndex.y]) * inNormal * inBoneWeight.y;\n#endif // ENABLE_NORMAL\n        if (BoneCount > 2)\n        {\n            objVert += BoneMatrixArray[boneIndex.z] * srcVert * inBoneWeight.z;\n#ifdef ENABLE_NORMAL\n            objNormal += mat3(BoneMatrixArray[boneIndex.z]) * inNormal * inBoneWeight.z;\n#endif // ENABLE_NORMAL\n            if (BoneCount > 3)\n            {\n                objVert += BoneMatrixArray[boneIndex.w] * srcVert * inBoneWeight.w;\n#ifdef ENABLE_NORMAL\n                objNormal += mat3(BoneMatrixArray[boneIndex.w]) * inNormal * inBoneWeight.w;\n#endif // ENABLE_NORMAL\n            }\n        }\n    }\n#ifdef ENABLE_NORMAL\n    objNormal = normalize(objNormal);\n#endif // ENABLE_NORMAL\n}\n\n#version 300 es\n// TexturedLighting vert-shader: ES3 //////////\n#ifndef ENABLE_SKINNING\nlayout(location = 0) in highp vec3 inVertex;\nlayout(location = 2) in mediump vec3 inNormal;\n#endif // ENABLE_SKINNING\n\nlayout(location = 3) in mediump vec2 inTexCoord;\nuniform lowp vec4 uColor;\n\n#ifdef ENABLE_PIXEL_LIGHTING\nout mediump vec3 ObjectspaceH;\n#ifdef ENABLE_PBR\nout mediump vec3 ObjectspaceV;\n#endif // ENABLE_PBR\nout mediump vec3 ObjectspaceN;\n#else\nuniform lowp vec4 ColorDiffuse;\nuniform mediump vec4 ColorSpecular;\nout lowp vec4 SpecularOut;\n#endif // ENABLE_PIXEL_LIGHTING\n\nuniform lowp vec3 ColorAmbient;\nuniform mediump vec3 EyePosition;\nuniform mediump vec3 LightPosition;\n\nout lowp vec4 DestinationColor;\nout mediump vec2 TextureCoordOut;\n\nuniform mat4 ModelviewProjection;\n\n#ifdef ENABLE_SHADOW_MAP\nuniform mat4 MatrixShadowmap;\nout highp vec4 LightcoordShadowmap;\n#endif\n\n#ifdef ENABLE_SHADOW_CSM\nuniform mat4 MatrixCSM[4];\nout highp vec4 LightcoordCSM[4];\n#endif\n\n#if defined(ENABLE_SHADOW_MAP) || defined(ENABLE_SHADOW_CSM)\nuniform highp float NormalBias;\n#endif\n\n#ifdef ENABLE_FOG\nuniform mediump vec4 FogPlane;\nuniform mediump float FogDepth;\nout mediump float FogDensity;\n#endif\n\nvoid main(void)\n{\n    highp vec4 objVert = vec4(inVertex, 1.0);\n    mediump vec3 objNormal = inNormal;\n    \n#ifdef ENABLE_SKINNING\n    if (BoneCount > 0)\n    {\n        ComputeSkinningVertex(objVert, objNormal);\n    }\n#endif\n\n    mediump vec3 L = LightPosition;\n    mediump vec3 E = normalize(EyePosition - objVert.xyz);\n#ifdef ENABLE_PIXEL_LIGHTING\n    ObjectspaceH = normalize(L + E);\n    #ifdef ENABLE_PBR\n    ObjectspaceV = E;\n    #endif\n    ObjectspaceN = objNormal;\n#else\n    #ifdef BLINN_PHONG_SPECULAR\n    mediump vec3 H = normalize(L + E);\n    mediump float sf = max(0.0, dot(objNormal, H));\n    #else\n    mediump vec3 R = reflect(-L, objNormal);\n    mediump float sf = max(0.0, dot(R, E));\n    #endif\n\n    sf = pow(sf, ColorSpecular.w);\n    SpecularOut = vec4(ColorSpecular.rgb * sf, 0.0);\n    \n    mediump float df = max(0.0, dot(objNormal, L));\n    DestinationColor = vec4(ColorAmbient + ColorDiffuse.rgb * df, ColorDiffuse.a);\n#endif\n    \n#ifdef ENABLE_SHADOW_MAP\n    vec3 biasedVertMap = objVert.xyz + objNormal * NormalBias;\n    LightcoordShadowmap = MatrixShadowmap * vec4(biasedVertMap, 1.0);\n#endif\n    \n#ifdef ENABLE_SHADOW_CSM\n    vec3 biasedVertCSM = objVert.xyz + objNormal * NormalBias;\n    LightcoordCSM[0] = MatrixCSM[0] * vec4(biasedVertCSM, 1.0);\n    LightcoordCSM[1] = MatrixCSM[1] * vec4(biasedVertCSM, 1.0);\n    LightcoordCSM[2] = MatrixCSM[2] * vec4(biasedVertCSM, 1.0);\n    LightcoordCSM[3] = MatrixCSM[3] * vec4(biasedVertCSM, 1.0);\n#endif\n\n#ifdef ENABLE_FOG\n    mediump float DepthInFog = dot(FogPlane.xyz, objVert.xyz) + FogPlane.w;\n    FogDensity = DepthInFog / FogDepth;\n#endif\n    \n    TextureCoordOut = inTexCoord;\n    gl_Position = ModelviewProjection * objVert;\n}\n\n","#version 300 es\n\n// TexturedLighting frag-shader: ES3 //////////\n#ifndef ENABLE_PIXEL_LIGHTING\n\nprecision mediump float;\n\nuniform lowp vec3 ColorAmbient;\t\t// ambient RGB \n\nin lowp vec4 SpecularOut;\t// separate specular added\nin lowp vec4 DestinationColor;\n\n// no pre-multiply alpha\n// lit result by per-vertex\nlowp vec4 ComputePixelLit(in lowp vec4 texDiffuse)\n{\n\tlowp vec4 result = texDiffuse * DestinationColor;\n\tresult.rgb += SpecularOut.rgb;\n\treturn result;\n}\n\nlowp vec4 ComputePixelUnlit(in lowp vec4 texDiffuse)\n{\n\t// unlit = ambient \n\treturn texDiffuse * vec4(ColorAmbient, DestinationColor.a);\n}\n#endif // ENABLE_PIXEL_LIGHTING\n\nin mediump vec2 TextureCoordOut;\nuniform sampler2D SamplerDiffuse;\t// GL_TEXTURE0\n\n#ifdef ENABLE_FOG\nin mediump float FogDensity;\t\t// fog density [0,1]\nuniform lowp vec3 FogColor;\n#endif // ENABLE_FOG\n\n#ifdef ENABLE_SHADOW_MAP\nin highp vec4 LightcoordShadowmap;\t// light-space coordinate-system\n#endif // ENABLE_SHADOW_MAP\n\n#ifdef ENABLE_SHADOW_CSM\nin highp vec4 LightcoordCSM[4];\t// light-space coordinate-system\nuniform highp vec4 DepthCSM;\t\t\t// depth clip-plane\n#endif // ENABLE_SHADOW_CSM\n\n#if defined(ENABLE_SHADOW_MAP) || defined(ENABLE_SHADOW_CSM)\nvoid ComputeShadowPCF(inout lowp vec4 texResult, in highp vec4 lightCoord);\n#endif // ENABLE_SHADOW_MAP or ENABLE_SHADOW_CSM\n\nout vec4 fragColor;\n\nvoid main(void)\n{\n\tlowp vec4 texResult = texture(SamplerDiffuse, TextureCoordOut);\t// tex-lookup\n#ifdef ENABLE_TEXTURE0_BGRA\t// iOS, macOS: CVPixelBuffer is BGRA, not RGBA\n\ttexResult = texResult.bgra;\n#endif // ENABLE_TEXTURE0_BGRA\n\n#ifdef ENABLE_ALPHA_TEST\n\tif (texResult.a < 0.5)\n\t\tdiscard;\n#endif // ENABLE_ALPHA_TEST\n\t\n\t////////// shadow map //////////\n#if defined(ENABLE_SHADOW_MAP) || defined(ENABLE_SHADOW_CSM)\n\t#ifdef ENABLE_SHADOW_CSM\n\t\thighp vec4 lightCoord = LightcoordCSM[3];\n\t\tif (gl_FragCoord.z < DepthCSM.x) {\n\t\t\tlightCoord = LightcoordCSM[0];\n\t\t}\n\t\telse if (gl_FragCoord.z < DepthCSM.y) {\n\t\t\tlightCoord = LightcoordCSM[1];\n\t\t}\n\t\telse if (gl_FragCoord.z < DepthCSM.z) {\n\t\t\tlightCoord = LightcoordCSM[2];\n\t\t}\n\t\telse {\n\t\t\tlightCoord = LightcoordCSM[3];\n\t\t}\n\t#else\n\t\thighp vec4 lightCoord = LightcoordShadowmap;\n\t#endif // ENABLE_SHADOW_CSM\n\t\n\tif (lightCoord.s < 0.0 || lightCoord.t < 0.0 || lightCoord.s > 1.0 || lightCoord.t > 1.0) {\n\t\ttexResult = ComputePixelLit(texResult);\t\t// lit area\n\t} else {\n\t\tComputeShadowPCF(texResult, lightCoord); \t// shadow area with PCF\n\t}\n\n#else\n    texResult = ComputePixelLit(texResult);\n#endif // ENABLE_SHADOW_MAP or ENABLE_SHADOW_CSM\n\n#ifdef ENABLE_FOG\n\t// Perform depth test and clamp the values\n\tlowp float fFogBlend = clamp(FogDensity + 1.0 - texResult.a, 0.0, 1.0);\n\ttexResult.rgb = mix(texResult.rgb, FogColor, fFogBlend); \n#endif // ENABLE_FOG\n\n\tfragColor = texResult;\n}\n\n")
